targets.rawSql:
SELECT logtime, CAST(VARIABLE_VALUE AS DECIMAL(10,2)) "Connections"
FROM `${compartment}#${display_name}`.global_status
where logtime > NOW() - INTERVAL 6 HOUR and VARIABLE_NAME in ('Threads_connected');

SELECT logtime, CAST(VARIABLE_VALUE AS DECIMAL(10,2)) "Abort Connect"
FROM `${compartment}#${display_name}`.global_status
where logtime > NOW() - INTERVAL 6 HOUR and VARIABLE_NAME in ('Aborted_connects');
